-- ============================================================================
-- 107 - Bulk approve champion_tags (2026-07-11). Promotes the full advisor-
-- reviewed proposed corpus to approved. Source of truth: master worksheet
-- DB_Champion_Tags (v4.82), where all proposed rows were flipped to approved
-- after a spot-check (34 samples, 32/34 clean) + systematic quality sweeps.
--
-- Rows resolved vs live champions(+aliases) and tags BY NAME. INSERTs net-new
-- approved pairs AND PROMOTES existing live 'proposed' pairs to 'approved'.
-- ON CONFLICT DO UPDATE is guarded by status='proposed' so it NEVER downgrades
-- an existing 'approved'/'rejected' row. Deduped per (champion_id, tag_id).
--
-- source_type/target_type normalized to the live CHECK-constraint sets:
--   'skill_extraction' -> 'human_observation' (170 rows)
--   target 'self'      -> 'unknown'            (6 rows)
--
-- NOT included: 222 worksheet-approved rows whose TAG is absent from the live
-- tags vocab (Increase ACC, Revive on Death, Steal Buffs, Taunt, Increase RES,
-- Poison Sensitivity, ...). Those need tag-vocab seeding first (surfaced gap).
-- ============================================================================
insert into champion_tags
  (champion_id, tag_id, status, source_type, source_note, proposed_by, proposed_at,
   ascension_required, champion_form, target_type, chance_unbooked, chance_booked,
   approved_by, approved_at)
